Here's a pattern for testing async code with cancellation and timeouts in MSTest:

```csharp
[TestClass]
public class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("http://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsHttpRequestException_OnFailure()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("http://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOperationCanceled_WhenAlreadyCanceled()
    {
        var handler = new MockHttpMessageHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("http://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // failsafe so test doesn't hang forever
    public async Task FetchAsync_ThrowsOperationCanceled_WhenCanceledDuringRequest()
    {
        using var cts = new CancellationTokenSource();
        var handler = new DelayedHandler(cts); // cancels mid-flight
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("http://example.com", cts.Token));
    }

    // --- Test helpers ---

    private class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode)
        {
            _content = content;
            _statusCode = statusCode;
        }

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            var response = new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
            return Task.FromResult(response);
        }
    }

    private class DelayedHandler : HttpMessageHandler
    {
        private readonly CancellationTokenSource _cts;
        public DelayedHandler(CancellationTokenSource cts) => _cts = cts;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            _cts.CancelAfter(50); // cancel shortly after request starts
            await Task.Delay(10_000, cancellationToken); // simulate slow response
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key takeaways:**

- **`[Timeout(5000)]`** — guards against hanging tests; MSTest cancels the test after the specified milliseconds.
- **Mock `HttpMessageHandler`** — lets you control responses without hitting the network.
- **Pre-canceled token** — verifies immediate cancellation.
- **`CancelAfter`** in a delayed handler — simulates cancellation arriving mid-request, producing `TaskCanceledException`.
- Always use `async Task` (not `async void`) for test methods.
